import argparse
import os
import subprocess
import sys
from pathlib import Path
from shutil import make_archive


def run(cmd, cwd=None):
    print(f"+ {' '.join(cmd)}", flush=True)
    subprocess.run(cmd, cwd=cwd, check=True)


def main():
    parser = argparse.ArgumentParser(description="CI/CD deployment automation")
    parser.add_argument("--requirements", default="requirements.txt", help="Path to requirements.txt")
    parser.add_argument("--tests", nargs="*", default=["pytest", "-q"], help="Test command")
    parser.add_argument("--package-name", default="deployment_package", help="Output package name")
    parser.add_argument("--package-root", default=".", help="Directory to package")
    args = parser.parse_args()

    req_path = Path(args.requirements)
    if not req_path.is_file():
        raise FileNotFoundError(f"Requirements file not found: {req_path}")

    run([sys.executable, "-m", "pip", "install", "--upgrade", "pip"])
    run([sys.executable, "-m", "pip", "install", "-r", str(req_path)])

    if args.tests:
        run(args.tests)

    package_root = Path(args.package_root).resolve()
    if not package_root.exists():
        raise FileNotFoundError(f"Package root not found: {package_root}")

    output_base = str(Path(args.package_name).resolve())
    archive_path = make_archive(output_base, "zip", root_dir=str(package_root))
    print(f"Created package: {archive_path}", flush=True)


if __name__ == "__main__":
    main()